import json

def export_user_data(user_id: str) -> bytes:
    """
    Export all user data in machine-readable JSON format.
    Format must be interoperable (JSON, CSV, XML — not PDF).
    """
    access_resp = handle_access_request(user_id)
    export = {
        "schema_version": "1.0",
        "exported_at": _now_iso(),
        "data": access_resp.categories,
    }
    return json.dumps(export, indent=2, ensure_ascii=False).encode("utf-8")

import re, hashlib, logging

_PII_PATTERNS = [
    re.compile(r"\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}\b"),  # email
    re.compile(r"\b\d{3}-\d{2}-\d{4}\b"),                                   # SSN
    re.compile(r"\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14})\b"),           # CC
    re.compile(r"\b(sk-[a-zA-Z0-9]{32,}|AIza[0-9A-Za-z\-_]{35})\b"),         # API keys
]

def scrub_for_log(text: str) -> str:
    for pattern in _PII_PATTERNS:
        text = pattern.sub("[REDACTED]", text)
    return text

def privacy_safe_log(logger: logging.Logger, level: str,
                     message: str, **fields) -> None:
    """Log with all field values scrubbed for PII."""
    safe_fields = {k: scrub_for_log(str(v)) for k, v in fields.items()}
    # Hash any user_id fields to pseudonymise
    if "user_id" in safe_fields:
        safe_fields["user_id"] = hashlib.sha256(
            safe_fields["user_id"].encode()).hexdigest()[:12]
    getattr(logger, level)(scrub_for_log(message), extra=safe_fields)
